Without django-pydantic-client      <pre><code>def signup(request):
    import json
    try:
        body = json.loads(request.body)
    except json.JSONDecodeError:
        return JsonResponse({"error": "bad json"}, status=400)

    username = body.get("username")
    email    = body.get("email")
    age      = body.get("age")

    if not username:
        return JsonResponse({"error": "username required"}, status=400)
    if not email or "@" not in email:
        return JsonResponse({"error": "bad email"}, status=400)
    if not isinstance(age, int) or age &lt; 0:
        return JsonResponse({"error": "bad age"}, status=400)

    # finally do something useful
</code></pre>        With django-pydantic-client      <pre><code># schema.py
from pydantic import EmailStr, Field
